sinks.expression:
wp_send_json_error(
					array(
						'message' => esc_html__( 'You don’t have access to this page. Please contact the administrator of this website for further assistance.', 'sg-security' ),
					),
					403
				)

array_map(
            function ($translation) {
                if (!empty($translation)) {
                    for ($i = 2; $i < count($translation); $i++) {
                        if (isset($translation[$i]) && empty($translation[$i])) {
                            $translation[$i] = $translation[0];
                        }
                    }
                    array_shift($translation);
                }

                return $translation;
            },
            $translations
        )

wp_remote_post(
				self::API_URL . '/auth/get_authenticated_response',
				array(
					'timeout' => 10,
					'body' => json_encode(
						array( 'url' => home_url() )
					),
					'sslverify' => false,
				)
			)
